+func reloadConfigTransactional(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), statusManager *reloadStatusManager, initial bool, rls ...reloader) (err error) {
+	logger.Info("Loading configuration file", "filename", filename)
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+	}()
+
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		if !initial {
+			statusManager.Record(newReloadFailure("load_error", err, "", nil, nil, false, false))
+		}
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	applied := make([]string, 0, len(rls))
+	timings := make(map[string]float64, len(rls))
+	for _, rl := range rls {
+		started := time.Now()
+		applyErr := rl.reloader(conf)
+		timings[rl.name] = float64(time.Since(started)) / float64(time.Millisecond)
+		if applyErr == nil {
+			applied = append(applied, rl.name)
+			continue
+		}
+
+		rollbackAttempted := len(applied) > 0
+		rollbackSuccessful := false
+		category := "apply_error"
+		message := applyErr.Error()
+		if rollbackAttempted {
+			rollbackSuccessful = true
+			previous := statusManager.LastGood()
+			if previous == nil {
+				rollbackSuccessful = false
+				message += "; no last known-good configuration is available"
+			} else {
+				for _, rollbackReloader := range rls {
+					if rollbackErr := rollbackReloader.reloader(previous); rollbackErr != nil {
+						rollbackSuccessful = false
+						message += fmt.Sprintf("; rollback of %s failed: %v", rollbackReloader.name, rollbackErr)
+						break
+					}
+				}
+			}
+			if !rollbackSuccessful {
+				category = "rollback_error"
+			}
+		}
+		if !initial {
+			statusManager.Record(newReloadFailure(category, fmt.Errorf("%s", message), rl.name, applied, timings, rollbackAttempted, rollbackSuccessful))
+		}
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, applyErr)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	statusManager.SetLastGood(conf)
+	if !initial {
+		statusManager.Record(web.ReloadStatus{
+			LastReloadID:         time.Now().UTC().Format(time.RFC3339Nano),
+			LastReloadSuccessful: true,
+			ErrorCategory:        "none",
+			AppliedReloaders:     applied,
+			ReloaderTimingsMS:    timings,
+		})
+	}
+	return nil
+}
+
+func newReloadFailure(category string, err error, failedReloader string, applied []string, timings map[string]float64, rollbackAttempted, rollbackSuccessful bool) web.ReloadStatus {
+	return web.ReloadStatus{
+		LastReloadID:         time.Now().UTC().Format(time.RFC3339Nano),
+		LastReloadSuccessful: false,
+		ErrorCategory:        category,
+		ErrorMessage:         err.Error(),
+		AppliedReloaders:     applied,
+		RollbackAttempted:    rollbackAttempted,
+		RollbackSuccessful:   rollbackSuccessful,
+		FailedReloader:       failedReloader,
+		ReloaderTimingsMS:    timings,
+	}
+}
