+func newReloadStatusManager(path string, enabled bool, logger *slog.Logger) *reloadStatusManager {
+	m := &reloadStatusManager{
+		path:    path,
+		enabled: enabled,
+		logger:  logger,
+		status: web.ReloadStatus{
+			ErrorCategory:     "none",
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMS: map[string]float64{},
+		},
+	}
+	if !enabled {
+		return m
+	}
+
+	b, err := os.ReadFile(path)
+	if err != nil {
+		if !os.IsNotExist(err) {
+			logger.Warn("Unable to read persisted reload status", "err", err)
+		}
+		return m
+	}
+	var status web.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil || !validReloadStatus(status) {
+		if err == nil {
+			err = os.ErrInvalid
+		}
+		logger.Warn("Ignoring invalid persisted reload status", "err", err)
+		return m
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]float64{}
+	}
+	m.status = status
+	return m
+}
+
+func validReloadStatus(status web.ReloadStatus) bool {
+	switch status.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+func (m *reloadStatusManager) Get() web.ReloadStatus {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+	return cloneReloadStatus(m.status)
+}
+
+func cloneReloadStatus(status web.ReloadStatus) web.ReloadStatus {
+	status.AppliedReloaders = slices.Clone(status.AppliedReloaders)
+	status.ReloaderTimingsMS = make(map[string]float64, len(status.ReloaderTimingsMS))
+	for name, timing := range status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[name] = timing
+	}
+	return status
+}
+
+func (m *reloadStatusManager) SetLastGood(conf *config.Config) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	m.lastGood = conf
+}
+
+func (m *reloadStatusManager) LastGood() *config.Config {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+	return m.lastGood
+}
+
+func (m *reloadStatusManager) Record(status web.ReloadStatus) {
+	m.mu.Lock()
+	m.status = cloneReloadStatus(status)
+	if m.enabled {
+		m.persistLocked()
+	}
+	m.mu.Unlock()
+}
